@property
def memory_allocated_bytes(self) -> int:
    """Total allocated memory including quantization metadata."""
    k_v_bytes = 2 * self.batch_size * self.num_heads * self.max_seq_len * self.head_dim
    # int8 for K and V
    scale_bytes = 2 * self.batch_size * self.num_heads * self.max_seq_len * self.head_dim * 2
    # float16 scales for K and V (one per channel per position)
    return k_v_bytes + scale_bytes

@property
def memory_savings_vs_fp16(self) -> float:
    """Fraction of memory saved vs. full fp16 cache."""
    fp16_bytes = 2 * self.batch_size * self.num_heads * self.max_seq_len * self.head_dim * 2
    return 1.0 - self.memory_allocated_bytes / fp16_bytes
